import{c as s,Q as e,j as t,m as n}from"./chunks/framework.BPKcPtvA.js";const k=JSON.parse('{"title":"@muhaven/mcp — read-only mode","description":"Restrict your MCP install to 7 read-only tools for shared or curated deployments.","frontmatter":{"title":"@muhaven/mcp — read-only mode","description":"Restrict your MCP install to 7 read-only tools for shared or curated deployments."},"headers":[],"relativePath":"mcp/read-only-mode.md","filePath":"mcp/read-only-mode.md","lastUpdated":1778951051000}'),i={name:"mcp/read-only-mode.md"};function o(l,a,r,h,p,d){return e(),t("div",null,[...a[0]||(a[0]=[n(`<h1 id="read-only-mode" tabindex="-1">Read-only mode <a class="header-anchor" href="#read-only-mode" aria-label="Permalink to &quot;Read-only mode&quot;">​</a></h1><p>When <code>MUHAVEN_READ_ONLY=true</code> is set in the broker env at startup, only the <strong>seven <code>muhaven.read.*</code> tools</strong> are registered. The position, policy, issuer, and governance groups are not even surfaced to the host LLM — the tool catalog the LLM sees doesn&#39;t mention them.</p><p>This is defense in depth for deployments where you want to allow LLM visibility but never LLM-driven mutation.</p><h2 id="when-to-use-it" tabindex="-1">When to use it <a class="header-anchor" href="#when-to-use-it" aria-label="Permalink to &quot;When to use it&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Scenario</th><th>Why read-only</th></tr></thead><tbody><tr><td>Shared workstation (e.g., investor portal in a brokerage office)</td><td>LLM can answer client questions; can&#39;t accidentally move funds.</td></tr><tr><td>Investor&#39;s own laptop with auto-LLM-batch jobs</td><td>&quot;Every Friday, summarize my MuHaven portfolio in a weekly email.&quot; No risk of jailbroken summary auto-trading.</td></tr><tr><td>Demo / training environments</td><td>Show the agentic surface without giving the demo audience signing capability.</td></tr><tr><td>Compliance officer who needs read access to their own issuer audit</td><td>The local broker only registers read tools — no risk of accidental signing.</td></tr></tbody></table><h2 id="how-to-enable" tabindex="-1">How to enable <a class="header-anchor" href="#how-to-enable" aria-label="Permalink to &quot;How to enable&quot;">​</a></h2><p>Set the env var before starting the broker:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> MUHAVEN_READ_ONLY</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">true</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">muhaven-broker</span></span></code></pre></div><p>Or inline:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">MUHAVEN_READ_ONLY</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">true</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> muhaven-broker</span></span></code></pre></div><p>The broker prints the read-only flag on startup:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[12:01] broker: READ-ONLY MODE (only muhaven.read.* tools registered)</span></span></code></pre></div><p>The MCP server queries the broker on startup to learn the read-only flag, then filters its tool registry accordingly. The host LLM&#39;s tool catalog will list the 7 read tools and nothing else.</p><h2 id="what-the-llm-sees" tabindex="-1">What the LLM sees <a class="header-anchor" href="#what-the-llm-sees" aria-label="Permalink to &quot;What the LLM sees&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&gt; What MuHaven tools do you have?</span></span>
<span class="line"><span></span></span>
<span class="line"><span>I have these MuHaven tools available:</span></span>
<span class="line"><span>- muhaven.read.portfolio</span></span>
<span class="line"><span>- muhaven.read.yields</span></span>
<span class="line"><span>- muhaven.read.distribution</span></span>
<span class="line"><span>- muhaven.read.tokens</span></span>
<span class="line"><span>- muhaven.read.audit</span></span>
<span class="line"><span>- muhaven.read.protection_coverage</span></span>
<span class="line"><span>- muhaven.read.kyc_attestation</span></span>
<span class="line"><span></span></span>
<span class="line"><span>These are all read-only. I can show you portfolio state, yield</span></span>
<span class="line"><span>history, distribution status, and protection coverage, but I</span></span>
<span class="line"><span>can&#39;t propose any trades or policy changes from here.</span></span></code></pre></div><p>A jailbroken LLM can&#39;t ask for a tool that isn&#39;t registered. There&#39;s no &quot;force the tool registration&quot; backdoor — the registry is built at startup from the broker&#39;s flag and stays immutable for the lifetime of the MCP server process.</p><h2 id="what-still-works" tabindex="-1">What still works <a class="header-anchor" href="#what-still-works" aria-label="Permalink to &quot;What still works&quot;">​</a></h2><p>All seven read tools function normally:</p><ul><li><code>muhaven.read.portfolio</code> — aggregate token list + <code>ebool</code> flags.</li><li><code>muhaven.read.yields</code> — per-token yield history.</li><li><code>muhaven.read.distribution</code> — epoch status.</li><li><code>muhaven.read.tokens</code> — RWA tokens you hold.</li><li><code>muhaven.read.audit</code> — your tiered-autonomy audit log.</li><li><code>muhaven.read.protection_coverage</code> — DefaultProtection state for a token.</li><li><code>muhaven.read.kyc_attestation</code> — KYC attestation registry status.</li></ul><p>The privacy invariants of each tool are unchanged — they were already read-only in the no-decrypt sense. Read-only mode just removes the <em>propose</em> surface.</p><h2 id="what-it-doesn-t-do" tabindex="-1">What it doesn&#39;t do <a class="header-anchor" href="#what-it-doesn-t-do" aria-label="Permalink to &quot;What it doesn&#39;t do&quot;">​</a></h2><ul><li><strong>It doesn&#39;t disable the broker&#39;s <code>sign_hash</code> capability.</strong> The capability exists at the broker; it&#39;s only never invoked because no propose tool is registered.</li><li><strong>It doesn&#39;t block dashboard sign-in.</strong> Your MuHaven wallet + passkey still work fine for HavenBot, Telegram, and the dashboard — read-only is an MCP-instance-level flag.</li><li><strong>It doesn&#39;t prevent a separate non-read-only install.</strong> You can run two brokers in parallel (one on <code>MUHAVEN_BROKER_SOCKET=/tmp/muhaven-broker-ro.sock</code> with read-only, one default) and wire them to different host config entries.</li></ul><h2 id="running-parallel-read-only-full-installs" tabindex="-1">Running parallel read-only + full installs <a class="header-anchor" href="#running-parallel-read-only-full-installs" aria-label="Permalink to &quot;Running parallel read-only + full installs&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Terminal A — full broker on default socket</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">muhaven-broker</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Terminal B — read-only broker on a different socket</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> MUHAVEN_READ_ONLY</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">true</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> MUHAVEN_BROKER_SOCKET</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">/tmp/muhaven-broker-ro.sock</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">muhaven-broker</span></span></code></pre></div><p>Wire each to a different host config entry:</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;mcpServers&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;muhaven&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: { </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;command&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;muhaven-mcp&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> },</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;muhaven-ro&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">      &quot;command&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;muhaven-mcp&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">      &quot;env&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: { </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;MUHAVEN_BROKER_SOCKET&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;/tmp/muhaven-broker-ro.sock&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>Now in your host you have two MuHaven tool catalogs — one full, one read-only. You can call them by namespace prefix in your chat.</p><h2 id="where-next" tabindex="-1">Where next <a class="header-anchor" href="#where-next" aria-label="Permalink to &quot;Where next&quot;">​</a></h2><ul><li><a href="/mcp/tools">Tool catalog</a> — full schema for the 7 read tools.</li><li><a href="/mcp/broker">Broker daemon</a> — how the broker stores state.</li><li><a href="/mcp/playbook">Playbook</a> — read-mostly scenarios that work great in read-only mode.</li></ul>`,29)])])}const u=s(i,[["render",o]]);export{k as __pageData,u as default};
